def get_total_number_of_sequences(m, n):
    # Initialize a 2D array to store the number of sequences
    dp = [[0 for _ in range(n+1)] for _ in range(m+1)]
    
    # Base case: there is exactly one sequence of length 1 for each possible value
    for i in range(1, m+1):
        dp[i][1] = 1
    
    # Fill the dp table for lengths from 2 to n
    for length in range(2, n+1):
        for last in range(1, m+1):
            # Sum the number of sequences ending with a value less than or equal to last/2
            for prev in range(1, last//2 + 1):
